import{_ as o,c as e,o as l,a1 as t}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Мультиканальные платформы | Учебник Clawdbot","description":"Узнайте, как настроить и использовать мультиканальную систему Clawdbot, включая WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS и Android платформы.","frontmatter":{"title":"Мультиканальные платформы | Учебник Clawdbot","sidebarTitle":"Интеграция с популярными мессенджерами","subtitle":"Мультиканальные платформы","description":"Узнайте, как настроить и использовать мультиканальную систему Clawdbot, включая WhatsApp, Telegram, Slack, Discord, Google Chat, Signal, iMessage, LINE, WebChat, macOS, iOS и Android платформы.","tags":["channels","platforms","integration"],"order":60},"headers":[],"relativePath":"ru/moltbot/moltbot/platforms/index.md","filePath":"ru/moltbot/moltbot/platforms/index.md"}'),r={name:"ru/moltbot/moltbot/platforms/index.md"};function i(s,a,n,h,d,g){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="мультиканальные-платформы" tabindex="-1">Мультиканальные платформы <a class="header-anchor" href="#мультиканальные-платформы" aria-label="Permalink to &quot;Мультиканальные платформы&quot;">​</a></h1><p>Clawdbot через единую управляющую плоскость Gateway поддерживает различные каналы связи и платформы, позволяя вам взаимодействовать с AI-помощником на знакомом интерфейсе.</p><h2 id="обзор-главы" tabindex="-1">Обзор главы <a class="header-anchor" href="#обзор-главы" aria-label="Permalink to &quot;Обзор главы&quot;">​</a></h2><p>Эта глава представляет все каналы связи и платформы, поддерживаемые Clawdbot, включая мессенджеры (WhatsApp, Telegram, Slack, Discord и др.), мобильные узлы (iOS, Android) и десктопные приложения (macOS). Узнайте, как настроить эти каналы, чтобы AI-помощник бесшовно интегрировался в ваш ежедневный рабочий процесс.</p><h2 id="навигация-по-подпунктам" tabindex="-1">Навигация по подпунктам <a class="header-anchor" href="#навигация-по-подпунктам" aria-label="Permalink to &quot;Навигация по подпунктам&quot;">​</a></h2><h3 id="обзор-каналов" tabindex="-1">Обзор каналов <a class="header-anchor" href="#обзор-каналов" aria-label="Permalink to &quot;Обзор каналов&quot;">​</a></h3><ul><li><strong><a href="./channels-overview/">Обзор мультиканальной системы</a></strong> - Узнайте о всех каналах связи, поддерживаемых Clawdbot, и их особенностях, освойте базовые концепции настройки каналов.</li></ul><h3 id="мессенджеры" tabindex="-1">Мессенджеры <a class="header-anchor" href="#мессенджеры" aria-label="Permalink to &quot;Мессенджеры&quot;">​</a></h3><ul><li><strong><a href="./whatsapp/">WhatsApp</a></strong> - Настройка и использование канала WhatsApp (на базе Baileys), поддерживает подключение устройств и управление группами.</li><li><strong><a href="./telegram/">Telegram</a></strong> - Настройка и использование канала Telegram (на базе grammY Bot API), настройка Bot Token и Webhook.</li><li><strong><a href="./slack/">Slack</a></strong> - Настройка и использование канала Slack (на базе Bolt), интеграция в ваше рабочее пространство.</li><li><strong><a href="./discord/">Discord</a></strong> - Настройка и использование канала Discord (на базе discord.js), поддерживает серверы и каналы.</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Настройка и использование канала Google Chat, интеграция с Google Workspace.</li><li><strong><a href="./signal/">Signal</a></strong> - Настройка и использование канала Signal (на базе signal-cli), защищенная коммуникация с конфиденциальностью.</li><li><strong><a href="./imessage/">iMessage</a></strong> - Настройка и использование канала iMessage (эксклюзивно для macOS), интеграция с приложением Сообщения на macOS.</li><li><strong><a href="./line/">LINE</a></strong> - Настройка и использование канала LINE (Messaging API), взаимодействие с пользователями LINE.</li></ul><h3 id="веб-и-нативные-приложения" tabindex="-1">Веб и нативные приложения <a class="header-anchor" href="#веб-и-нативные-приложения" aria-label="Permalink to &quot;Веб и нативные приложения&quot;">​</a></h3><ul><li><strong><a href="./webchat/">Интерфейс WebChat</a></strong> - Используйте встроенный интерфейс WebChat для взаимодействия с AI-помощником, без необходимости настройки внешних каналов.</li><li><strong><a href="./macos-app/">Приложение macOS</a></strong> - Узнайте о функциях приложения macOS в строке меню, включая Voice Wake, Talk Mode и удаленное управление.</li><li><strong><a href="./ios-node/">Узел iOS</a></strong> - Настройте узел iOS для выполнения локальных операций на устройстве (Camera, Canvas, Voice Wake).</li><li><strong><a href="./android-node/">Узел Android</a></strong> - Настройте узел Android для выполнения локальных операций на устройстве (Camera, Canvas).</li></ul><h2 id="рекомендуемыи-порядок-обучения" tabindex="-1">Рекомендуемый порядок обучения <a class="header-anchor" href="#рекомендуемыи-порядок-обучения" aria-label="Permalink to &quot;Рекомендуемый порядок обучения&quot;">​</a></h2><p>В зависимости от вашего сценария использования, рекомендуется следующий порядок обучения:</p><h3 id="быстрое-начало-для-новичков" tabindex="-1">Быстрое начало для новичков <a class="header-anchor" href="#быстрое-начало-для-новичков" aria-label="Permalink to &quot;Быстрое начало для новичков&quot;">​</a></h3><p>Если вы впервые используете Clawdbot, рекомендуется следующий порядок обучения:</p><ol><li><strong><a href="./channels-overview/">Обзор мультиканальной системы</a></strong> - Сначала ознакомьтесь с общей архитектурой и концепцией каналов</li><li><strong><a href="./webchat/">Интерфейс WebChat</a></strong> - Самый простой способ начать использование без настройки</li><li><strong>Выберите популярный канал</strong> - Выберите в соответствии с вашими ежедневными привычками: <ul><li>Ежедневные переписки → <a href="./whatsapp/">WhatsApp</a> или <a href="./telegram/">Telegram</a></li><li>Командная работа → <a href="./slack/">Slack</a> или <a href="./discord/">Discord</a></li><li>Пользователи macOS → <a href="./imessage/">iMessage</a></li></ul></li></ol><h3 id="интеграция-мобильных-устроиств" tabindex="-1">Интеграция мобильных устройств <a class="header-anchor" href="#интеграция-мобильных-устроиств" aria-label="Permalink to &quot;Интеграция мобильных устройств&quot;">​</a></h3><p>Если вы хотите использовать Clawdbot на мобильных устройствах:</p><ol><li><strong><a href="./ios-node/">Узел iOS</a></strong> - Настройте локальные функции на iPhone/iPad</li><li><strong><a href="./android-node/">Узел Android</a></strong> - Настройте локальные функции на устройствах Android</li><li><strong><a href="./macos-app/">Приложение macOS</a></strong> - Используйте приложение macOS как центр управления</li></ol><h3 id="корпоративное-развертывание" tabindex="-1">Корпоративное развертывание <a class="header-anchor" href="#корпоративное-развертывание" aria-label="Permalink to &quot;Корпоративное развертывание&quot;">​</a></h3><p>Если вам нужно развернуть в командной среде:</p><ol><li><strong><a href="./slack/">Slack</a></strong> - Интеграция с рабочим пространством команды</li><li><strong><a href="./discord/">Discord</a></strong> - Создание сервера сообщества</li><li><strong><a href="./googlechat/">Google Chat</a></strong> - Интеграция с Google Workspace</li></ol><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><p>Перед началом изучения этой главы рекомендуется завершить:</p><ul><li><strong><a href="./../start/getting-started/">Быстрое начало</a></strong> - Завершите установку и базовую настройку Clawdbot</li><li><strong><a href="./../start/onboarding-wizard/">Мастер настройки</a></strong> - Завершите базовую настройку Gateway и каналов через мастера</li></ul><div class="tip custom-block"><p class="custom-block-title">Совет</p><p>Если вы уже завершили мастер настройки, некоторые каналы могут быть автоматически настроены. Вы можете пропустить повторяющиеся шаги настройки и сразу просмотреть расширенные функции конкретных каналов.</p></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После завершения изучения этой главы вы можете продолжить исследование:</p><ul><li><strong><a href="./../advanced/models-auth/">Модели AI и настройка аутентификации</a></strong> - Настройка различных поставщиков AI-моделей</li><li><strong><a href="./../advanced/session-management/">Управление сессиями и мульти-Agent</a></strong> - Изучение изоляции сессий и взаимодействия под-Agents</li><li><strong><a href="./../advanced/tools-browser/">Система инструментов</a></strong> - Использование автоматизации браузера, выполнения команд и других инструментов</li></ul><h2 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h2><details class="details custom-block"><summary>Могу ли я использовать несколько каналов одновременно?</summary><p>Да! Clawdbot поддерживает одновременное включение нескольких каналов. Вы можете принимать и отправлять сообщения на разных каналах, все сообщения обрабатываются через единый Gateway.</p></details><details class="details custom-block"><summary>Какой канал наиболее рекомендуется?</summary><p>Это зависит от вашего сценария использования:</p><ul><li><strong>WebChat</strong> - Самый простой, не требует настройки</li><li><strong>WhatsApp</strong> - Подходит для общения с друзьями и семьей</li><li><strong>Telegram</strong> - Стабильный Bot API, подходит для автоматических ответов</li><li><strong>Slack/Discord</strong> - Подходит для командной работы</li></ul></details><details class="details custom-block"><summary>Требуется ли оплата за настройку каналов?</summary><p>Большинство каналов бесплатны, но некоторые могут иметь стоимость:</p><ul><li>WhatsApp Business API - могут возникнуть расходы</li><li>Google Chat - требуется аккаунт Google Workspace</li><li>Другие каналы - обычно бесплатны, достаточно получить Bot Token</li></ul></details>',33)])])}const p=o(r,[["render",i]]);export{m as __pageData,p as default};
